#include <omp.h>

#if defined(__has_include)
#  if __has_include("../common.h")
#    include "../common.h"
#  elif __has_include("./common.h")
#    include "./common.h"
#  else
#    include "common.h"
#  endif
#else
#  include "../common.h"
#endif

void 
kernel_cpu(	int cores_arg,

			record *records,
			knode *knodes,
			long knodes_elem,

			int order,
			long maxheight,
			int count,

			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	int i, j;
	int order_limit = order;

#ifdef DEFAULT_ORDER
	if (order_limit > DEFAULT_ORDER)
		order_limit = DEFAULT_ORDER;
#endif
	if (order_limit < 0)
		order_limit = 0;

	if (cores_arg > 0)
		omp_set_num_threads(cores_arg);

	#pragma omp parallel for private(i, j) schedule(static)
	for (i = 0; i < count; i++) {
		for (j = 0; j < maxheight; j++) {
			long node = currKnode[i];
			long next = offset[i];
			int thid;

			for (thid = 0; thid < order_limit; thid++) {
				if ((knodes[node].keys[thid] <= keys[i]) &&
				    (knodes[node].keys[thid + 1] > keys[i])) {
					if (knodes[next].indices[thid] < knodes_elem) {
						next = knodes[next].indices[thid];
					}
				}
			}

			offset[i] = next;
			currKnode[i] = next;
		}

		for (j = 0; j < order_limit; j++) {
			if (knodes[currKnode[i]].keys[j] == keys[i]) {
				ans[i].value = records[knodes[currKnode[i]].indices[j]].value;
			}
		}
	}
}

