void 
kernel_cpu_2(	int cores_arg,

				knode *knodes,
				long knodes_elem,

				int order,
				long maxheight,
				int count,

				long *currKnode,
				long *offset,
				long *lastKnode,
				long *offset_2,
				int *start,
				int *end,
				int *recstart,
				int *reclength)
{
	int i, j;
	int order_limit = order;

#ifdef DEFAULT_ORDER
	if (order_limit > DEFAULT_ORDER)
		order_limit = DEFAULT_ORDER;
#endif
	if (order_limit < 0)
		order_limit = 0;

	if (cores_arg > 0)
		omp_set_num_threads(cores_arg);

	#pragma omp parallel for private(i, j) schedule(static)
	for (i = 0; i < count; i++) {
		for (j = 0; j < maxheight; j++) {
			long node_start = currKnode[i];
			long node_end = lastKnode[i];
			long next_start = offset[i];
			long next_end = offset_2[i];
			int thid;

			for (thid = 0; thid < order_limit; thid++) {
				if ((knodes[node_start].keys[thid] <= start[i]) &&
				    (knodes[node_start].keys[thid + 1] > start[i])) {
					if (knodes[node_start].indices[thid] < knodes_elem) {
						next_start = knodes[node_start].indices[thid];
					}
				}

				if ((knodes[node_end].keys[thid] <= end[i]) &&
				    (knodes[node_end].keys[thid + 1] > end[i])) {
					if (knodes[node_end].indices[thid] < knodes_elem) {
						next_end = knodes[node_end].indices[thid];
					}
				}
			}

			offset[i] = next_start;
			currKnode[i] = next_start;
			offset_2[i] = next_end;
			lastKnode[i] = next_end;
		}

		for (j = 0; j < order_limit; j++) {
			if (knodes[currKnode[i]].keys[j] == start[i]) {
				recstart[i] = knodes[currKnode[i]].indices[j];
			}
		}

		for (j = 0; j < order_limit; j++) {
			if (knodes[lastKnode[i]].keys[j] == end[i]) {
				reclength[i] = knodes[lastKnode[i]].indices[j] - recstart[i] + 1;
			}
		}
	}
}
